const router = createCommandRouter(handlers)

async function run() {
  try {
    await router()
  } catch (error) {
    if (error instanceof SupabaseError) {
      lib_core.setFailed(`${error.code}: ${error.message}`)
    } else {
      handleError(error)
    }
  }
}

